import React, { useState } from "react";
import "./style.css";
import { useNavigate } from "react-router-dom";
//import { response } from "express";
//import { application, json } from "express";



function Signin() {
    const navigate=useNavigate();
    const [username,setUsername]=useState("");
    const [password,setPassword]=useState("");

    const handleSubmit=async(e)=>{
        //e.preventDefault();
        console.log("sending data...");
        /*const response=await fetch("http://localhost:5000/signin",{
            method: "POST" ,
            headers: {"Content-Type":"application/json"},
            body:JSON.stringify({username,password})
        });
        const data=await response.json();
        console.log(data);*/
    };


    function GoToDashboard() {
            navigate('/dashboard');
    }

    return(
        <>
            <h1>Sign in</h1>
            <div className="signcontainer">
                
                <br/>
                <form action={'http://localhost:5000/signin'} method="POST" onSubmit={handleSubmit}>
                    <label htmlFor="username">Username:</label><br/>
                    <input type="text" name="username" id="username" onChange={(e)=>setUsername(e.target.value)}/><br/><br/>
                    <label htmlFor="password">Password:</label><br/>
                    <input type="password" name="password" id="password" onChange={(e)=>setPassword(e.target.value)}/>
                
                    <p>Don't have account? <a href="register.html">Register</a></p>
                    <button type="submit" onClick={GoToDashboard}>sign in</button>
                </form>
            </div>
        </>
    );
}

export default Signin;
